// app.config.ts (standalone)
export const appConfig: ApplicationConfig = {
  providers: [
    provideRouter(
      routes,
      withInMemoryScrolling({ anchorScrolling: 'enabled', scrollPositionRestoration: 'enabled' })
    ),
  ],
};

import { Component, inject } from '@angular/core';
import { Router } from '@angular/router';

@Component({ /* ... */ })
export class LoginComponent {
  private router = inject(Router);

  async onLogin(credentials: Credentials) {
    const success = await this.authService.login(credentials);
    if (success) {
      // Array form — builds the URL from segments
      this.router.navigate(['/dashboard']);

      // Or pass a full URL string
      // this.router.navigateByUrl('/dashboard');
    }
  }
}

// Programmatic equivalent
this.router.navigate(['/courses'], {
  queryParams: { category: 'beginner' },
  queryParamsHandling: 'merge',   // 'merge' | 'preserve' | ''
  fragment: 'results'
});

// Read current query params and fragment
import { ActivatedRoute } from '@angular/router';
route = inject(ActivatedRoute);
category = this.route.snapshot.queryParamMap.get('category');

// nav-bar.component.spec.ts
import { TestBed, ComponentFixture } from '@angular/core/testing';
import { RouterTestingModule } from '@angular/router/testing';
import { NavBarComponent } from './nav-bar.component';
import { Router } from '@angular/router';
import { By } from '@angular/platform-browser';

describe('NavBarComponent', () => {
  let fixture: ComponentFixture<NavBarComponent>;
  let router: Router;

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [
        NavBarComponent,
        RouterTestingModule.withRoutes([
          { path: 'home', component: NavBarComponent },
          { path: 'courses', component: NavBarComponent },
        ])
      ]
    }).compileComponents();

    fixture = TestBed.createComponent(NavBarComponent);
    router = TestBed.inject(Router);
    fixture.detectChanges();
  });

  it('renders internal links with routerLink', () => {
    const links = fixture.debugElement.queryAll(By.css('a[ng-reflect-router-link]'));
    expect(links.length).toBeGreaterThanOrEqual(3);
  });

  it('marks the active link with the active class', async () => {
    await router.navigateByUrl('/courses');
    fixture.detectChanges();
    const activeLinks = fixture.debugElement.queryAll(
      By.css('a.active')
    );
    expect(activeLinks.length).toBe(1);
    expect(activeLinks[0].nativeElement.getAttribute('href')).toBe('/courses');
  });

  it('uses href for external links', () => {
    const externalLink = fixture.debugElement.query(
      By.css('a[href^="https://"]')
    );
    expect(externalLink).toBeTruthy();
    expect(externalLink.nativeElement.getAttribute('rel')).toContain('noopener');
  });
});

/* Visually hidden until focused */
.skip-link {
  position: absolute;
  top: -100%;
  left: 0;
  padding: 0.5rem 1rem;
  background: #1d4ed8;
  color: #fff;
  font-weight: 600;
  z-index: 9999;
  transition: top 0.1s;
}
.skip-link:focus {
  top: 0;
}
